
  CREATE TABLE "DIRKSPZM32"."LVS_LHM_CFG" 
   (	"SID" VARCHAR2(2 CHAR) NOT NULL ENABLE, 
	"FIRMA_NR" NUMBER(2,0) NOT NULL ENABLE, 
	"LHM_NAME" VARCHAR2(50 CHAR) NOT NULL ENABLE, 
	"LHM_TEXT" VARCHAR2(60 CHAR), 
	"LHM_VOL_HOEHE" NUMBER(*,3), 
	"LHM_VOL_BREITE" NUMBER(*,3), 
	"LHM_VOL_TIEFE" NUMBER(*,3), 
	"LHM_GEW_KG" NUMBER(*,6), 
	"LHM_MENGE" NUMBER(*,3), 
	"LHM_ID_GUELTIG_TAGE" NUMBER(*,5), 
	"VERWALTET_VON" VARCHAR2(20 CHAR) DEFAULT 'ISI' NOT NULL ENABLE, 
	"HOST_REF_ID" VARCHAR2(10 CHAR), 
	"STAPELFAKTOR" NUMBER(*,5) DEFAULT 99 NOT NULL ENABLE, 
	"LHM_GEOM" VARCHAR2(20 CHAR), 
	"ISI_PARAMS" VARCHAR2(4000 CHAR)
   ) ;
ALTER TABLE "DIRKSPZM32"."LVS_LHM_CFG" ADD CONSTRAINT "CHK_LVS_LHM_CFG_GEOM" CHECK (LHM_GEOM in ('QUADER', 'ZYLINDER')) ENABLE;
ALTER TABLE "DIRKSPZM32"."LVS_LHM_CFG" ADD CONSTRAINT "PK_LVS_LHM_CFG" PRIMARY KEY ("LHM_NAME", "SID")
  USING INDEX  ENABLE;


